export const theme3Es = [
  { textFr: "Comment s'appelle la Constitution actuelle de la France ?", lang: 'es' as const, text: "¿Cómo se llama la Constitución actual de Francia?", explanation: "La Constitución actual de Francia es la Constitución de la V República, adoptada el 4 de octubre de 1958. Fue redactada bajo el impulso del general de Gaulle y constituye el texto fundamental de la organización política francesa.", choices: [{ id: 'a' as const, text: "La Constitución de la V República" }, { id: 'b' as const, text: "La Constitución de la IV República" }, { id: 'c' as const, text: "La Constitución de la III República" }, { id: 'd' as const, text: "La Constitución de la VI República" }] },
  { textFr: "Comment s'appelle le texte qui énonce les droits et devoirs des personnes résidant en France ?", lang: 'es' as const, text: "¿Cómo se llama el texto que enuncia los derechos y deberes de las personas que residen en Francia?", explanation: "La Carta de derechos y deberes del ciudadano francés es el texto que enuncia los derechos y deberes de las personas que residen en Francia. Se entrega a los candidatos a la naturalización.", choices: [{ id: 'a' as const, text: "La Carta de derechos y deberes del ciudadano francés" }, { id: 'b' as const, text: "El Código penal" }, { id: 'c' as const, text: "El Código del trabajo" }, { id: 'd' as const, text: "La Declaración Universal de los Derechos Humanos" }] },
  { textFr: "Concernant les droits individuels, quelle proposition est correcte ?", lang: 'es' as const, text: "Respecto a los derechos individuales, ¿qué afirmación es correcta?", explanation: "En Francia, cada persona tiene derechos individuales garantizados por la Constitución y la Declaración de los Derechos del Hombre. Entre estos derechos figuran la libertad de expresión, la libertad de conciencia y el derecho a la seguridad.", choices: [{ id: 'a' as const, text: "Cada persona tiene derecho a expresarse libremente dentro del respeto a la ley" }, { id: 'b' as const, text: "Los derechos individuales solo conciernen a los ciudadanos franceses" }, { id: 'c' as const, text: "Los derechos individuales no existen en Francia" }, { id: 'd' as const, text: "Solo los hombres se benefician de derechos individuales" }] },
  { textFr: "De quelle année date la Déclaration des droits de l'homme et du citoyen ?", lang: 'es' as const, text: "¿De qué año data la Declaración de los Derechos del Hombre y del Ciudadano?", explanation: "La Declaración de los Derechos del Hombre y del Ciudadano fue adoptada el 26 de agosto de 1789, durante la Revolución Francesa. Se considera un texto fundador de las libertades en Francia y en el mundo.", choices: [{ id: 'a' as const, text: "1789" }, { id: 'b' as const, text: "1791" }, { id: 'c' as const, text: "1804" }, { id: 'd' as const, text: "1958" }] },
  { textFr: "Lequel de ces droits est un droit fondamental ?", lang: 'es' as const, text: "¿Cuál de estos derechos es un derecho fundamental?", explanation: "La libertad de expresión es un derecho fundamental garantizado por la Declaración de los Derechos del Hombre y del Ciudadano de 1789 y por la Constitución francesa. Permite a cada persona expresar libremente sus ideas y opiniones.", choices: [{ id: 'a' as const, text: "La libertad de expresión" }, { id: 'b' as const, text: "El derecho a conducir sin permiso" }, { id: 'c' as const, text: "El derecho a no pagar impuestos" }, { id: 'd' as const, text: "El derecho a no respetar la ley" }] },
  { textFr: "Parmi ces textes, lequel garantit les droits et libertés en France ?", lang: 'es' as const, text: "Entre estos textos, ¿cuál garantiza los derechos y libertades en Francia?", explanation: "La Declaración de los Derechos del Hombre y del Ciudadano de 1789 es el texto fundador que garantiza los derechos y libertades en Francia. Está integrada en el bloque de constitucionalidad y tiene valor constitucional.", choices: [{ id: 'a' as const, text: "La Declaración de los Derechos del Hombre y del Ciudadano de 1789" }, { id: 'b' as const, text: "El Código de circulación" }, { id: 'c' as const, text: "El reglamento interno de las empresas" }, { id: 'd' as const, text: "El Código de comercio" }] },
  { textFr: "Qu'est-ce que la liberté d'expression ?", lang: 'es' as const, text: "¿Qué es la libertad de expresión?", explanation: "La libertad de expresión es el derecho de cada persona a expresar libremente sus opiniones e ideas, dentro del respeto a la ley. Está garantizada por la Declaración de los Derechos del Hombre y del Ciudadano de 1789.", choices: [{ id: 'a' as const, text: "El derecho a expresar libremente sus opiniones dentro del respeto a la ley" }, { id: 'b' as const, text: "El derecho a decir todo lo que se quiera sin ningún límite" }, { id: 'c' as const, text: "El derecho a publicar información secreta del Estado" }, { id: 'd' as const, text: "El derecho reservado únicamente a los periodistas" }] },
  { textFr: "Quel droit permet à une personne de se défendre devant la justice ?", lang: 'es' as const, text: "¿Qué derecho permite a una persona defenderse ante la justicia?", explanation: "El derecho a la defensa permite a toda persona defenderse ante la justicia, ser asistida por un abogado y beneficiarse de un juicio justo. Es un derecho fundamental garantizado por la Constitución.", choices: [{ id: 'a' as const, text: "El derecho a la defensa" }, { id: 'b' as const, text: "El derecho de huelga" }, { id: 'c' as const, text: "El derecho al voto" }, { id: 'd' as const, text: "El derecho a manifestarse" }] },
  { textFr: "Quel est le texte fondateur établissant les droits et les devoirs de chaque citoyen ?", lang: 'es' as const, text: "¿Cuál es el texto fundador que establece los derechos y deberes de cada ciudadano?", explanation: "La Declaración de los Derechos del Hombre y del Ciudadano de 1789 es el texto fundador que establece los derechos y deberes de cada ciudadano. Fue adoptada durante la Revolución Francesa y forma parte del bloque de constitucionalidad.", choices: [{ id: 'a' as const, text: "La Declaración de los Derechos del Hombre y del Ciudadano de 1789" }, { id: 'b' as const, text: "El Código civil de 1804" }, { id: 'c' as const, text: "La Constitución de 1958" }, { id: 'd' as const, text: "El Tratado de Maastricht" }] },
  { textFr: "Quel texte a été adopté pendant la Révolution française ?", lang: 'es' as const, text: "¿Qué texto fue adoptado durante la Revolución Francesa?", explanation: "La Declaración de los Derechos del Hombre y del Ciudadano fue adoptada el 26 de agosto de 1789, durante la Revolución Francesa. Proclama los derechos naturales e imprescriptibles del hombre.", choices: [{ id: 'a' as const, text: "La Declaración de los Derechos del Hombre y del Ciudadano" }, { id: 'b' as const, text: "La Constitución de la V República" }, { id: 'c' as const, text: "El Código civil" }, { id: 'd' as const, text: "El Tratado de Versalles" }] },
  { textFr: "Quelle liberté permet à une personne de ne pas avoir de religion ?", lang: 'es' as const, text: "¿Qué libertad permite a una persona no tener religión?", explanation: "La libertad de conciencia permite a cada persona creer o no creer en una religión. Está garantizada por la ley de 1905 sobre la separación de las Iglesias y el Estado y por la Constitución francesa.", choices: [{ id: 'a' as const, text: "La libertad de conciencia" }, { id: 'b' as const, text: "La libertad de expresión" }, { id: 'c' as const, text: "La libertad de prensa" }, { id: 'd' as const, text: "La libertad de circulación" }] },
  { textFr: "Une femme peut avorter :", lang: 'es' as const, text: "Una mujer puede abortar:", explanation: "En Francia, una mujer puede abortar libremente hasta las 14 semanas de embarazo (desde la ley del 2 de marzo de 2022). Este derecho está garantizado por la ley y fue constitucionalizado en 2024.", choices: [{ id: 'a' as const, text: "Libremente, dentro de los plazos previstos por la ley" }, { id: 'b' as const, text: "Únicamente con el acuerdo de su marido" }, { id: 'c' as const, text: "Solo en caso de peligro para su vida" }, { id: 'd' as const, text: "El aborto está prohibido en Francia" }] },
  { textFr: "Est-il toujours possible de divorcer ?", lang: 'es' as const, text: "¿Es siempre posible divorciarse?", explanation: "Sí, en Francia siempre es posible divorciarse. El divorcio puede ser solicitado por uno o ambos cónyuges. Existen varios procedimientos: por consentimiento mutuo, por culpa, por alteración definitiva del vínculo conyugal, etc.", choices: [{ id: 'a' as const, text: "Sí, el divorcio siempre es posible en Francia" }, { id: 'b' as const, text: "No, el divorcio está prohibido en Francia" }, { id: 'c' as const, text: "Solo si ambos cónyuges están de acuerdo" }, { id: 'd' as const, text: "Solo después de 10 años de matrimonio" }] },
  { textFr: "La peine de mort est :", lang: 'es' as const, text: "La pena de muerte es:", explanation: "La pena de muerte fue abolida en Francia el 9 de octubre de 1981, bajo la presidencia de François Mitterrand, gracias a la acción del ministro de Justicia Robert Badinter. Su abolición está inscrita en la Constitución desde 2007.", choices: [{ id: 'a' as const, text: "Abolida en Francia desde 1981" }, { id: 'b' as const, text: "Todavía aplicada para los crímenes más graves" }, { id: 'c' as const, text: "Autorizada únicamente en tiempo de guerra" }, { id: 'd' as const, text: "Suspendida temporalmente" }] },
  { textFr: "Concernant les limites aux libertés individuelles, quelle proposition est correcte ?", lang: 'es' as const, text: "Respecto a los límites de las libertades individuales, ¿qué afirmación es correcta?", explanation: "Las libertades individuales pueden ser limitadas para proteger el orden público y los derechos de los demás. Estas limitaciones deben estar previstas por la ley y ser proporcionadas al objetivo perseguido.", choices: [{ id: 'a' as const, text: "Las libertades pueden ser limitadas para proteger el orden público y los derechos de los demás" }, { id: 'b' as const, text: "Las libertades individuales son absolutas y nunca pueden ser limitadas" }, { id: 'c' as const, text: "Solo el Presidente puede limitar las libertades individuales" }, { id: 'd' as const, text: "Las libertades individuales no conciernen a los extranjeros" }] },
  { textFr: "En France, est-ce légal d'être marié à plusieurs personnes en même temps ?", lang: 'es' as const, text: "En Francia, ¿es legal estar casado con varias personas al mismo tiempo?", explanation: "No, la poligamia está prohibida en Francia. El Código civil impone la monogamia: una persona solo puede estar casada con una única persona a la vez. La bigamia es un delito castigado por la ley.", choices: [{ id: 'a' as const, text: "No, está prohibido por la ley" }, { id: 'b' as const, text: "Sí, si todas las personas están de acuerdo" }, { id: 'c' as const, text: "Sí, pero solo para los extranjeros" }, { id: 'd' as const, text: "Sí, desde la ley de 2013" }] },
  { textFr: "Faut-il réduire ses déchets ?", lang: 'es' as const, text: "¿Hay que reducir los residuos?", explanation: "Sí, la reducción de residuos es una obligación ciudadana y medioambiental. La Carta del Medio Ambiente, integrada en el bloque de constitucionalidad, prevé que cada persona debe contribuir a la preservación del medio ambiente.", choices: [{ id: 'a' as const, text: "Sí, es un deber de cada ciudadano para proteger el medio ambiente" }, { id: 'b' as const, text: "No, no es una obligación" }, { id: 'c' as const, text: "Solo si el ayuntamiento lo impone" }, { id: 'd' as const, text: "No, es responsabilidad exclusiva de las empresas" }] },
  { textFr: "Jeter une bouteille dans la rue est :", lang: 'es' as const, text: "Tirar una botella en la calle es:", explanation: "Tirar una botella en la calle es una infracción castigada por la ley. Se trata de un vertido ilegal de residuos, sancionable con multa. Cada persona debe respetar la limpieza de los espacios públicos.", choices: [{ id: 'a' as const, text: "Prohibido y sancionable con multa" }, { id: 'b' as const, text: "Permitido si la botella es de plástico" }, { id: 'c' as const, text: "Tolerado en las grandes ciudades" }, { id: 'd' as const, text: "Permitido si no hay papelera cerca" }] },
  { textFr: "Pourquoi les libertés individuelles peuvent-elles être limitées ?", lang: 'es' as const, text: "¿Por qué pueden limitarse las libertades individuales?", explanation: "Las libertades individuales pueden ser limitadas para preservar el orden público y proteger los derechos y libertades de los demás. La ley fija estos límites de manera proporcionada.", choices: [{ id: 'a' as const, text: "Para preservar el orden público y proteger los derechos de los demás" }, { id: 'b' as const, text: "Para favorecer al gobierno en el poder" }, { id: 'c' as const, text: "Para impedir que los ciudadanos se expresen" }, { id: 'd' as const, text: "Las libertades individuales nunca pueden ser limitadas" }] },
  { textFr: "Que doit faire une personne en cas d'accident ?", lang: 'es' as const, text: "¿Qué debe hacer una persona en caso de accidente?", explanation: "En caso de accidente, toda persona debe llamar a los servicios de emergencia (el 15 para el SAMU, el 18 para los bomberos o el 112 para el número de emergencia europeo) y prestar asistencia a las víctimas en la medida de lo posible.", choices: [{ id: 'a' as const, text: "Llamar a los servicios de emergencia y prestar asistencia a las víctimas" }, { id: 'b' as const, text: "Seguir su camino sin detenerse" }, { id: 'c' as const, text: "Grabar la escena y publicarla en las redes sociales" }, { id: 'd' as const, text: "Esperar a que otra persona intervenga" }] },
  { textFr: "Que permet la citoyenneté française ?", lang: 'es' as const, text: "¿Qué permite la ciudadanía francesa?", explanation: "La ciudadanía francesa permite participar en la vida política del país, especialmente mediante el derecho al voto y el derecho a ser elegido. También confiere derechos civiles y sociales e implica deberes.", choices: [{ id: 'a' as const, text: "Votar y participar en la vida política del país" }, { id: 'b' as const, text: "No pagar impuestos" }, { id: 'c' as const, text: "No respetar las leyes francesas" }, { id: 'd' as const, text: "Tener un empleo garantizado por el Estado" }] },
  { textFr: "Que risque une personne qui ne respecte pas la loi ?", lang: 'es' as const, text: "¿Qué le puede pasar a una persona que no respeta la ley?", explanation: "Una persona que no respeta la ley se expone a sanciones penales que pueden ir desde la multa hasta la prisión, según la gravedad de la infracción cometida (contravención, delito o crimen).", choices: [{ id: 'a' as const, text: "Sanciones que pueden ir desde la multa hasta la prisión" }, { id: 'b' as const, text: "Nada, no hay sanciones en Francia" }, { id: 'c' as const, text: "Únicamente una advertencia verbal" }, { id: 'd' as const, text: "La expulsión automática del territorio" }] },
  { textFr: "Quel est le rôle de la gendarmerie ?", lang: 'es' as const, text: "¿Cuál es el papel de la gendarmería?", explanation: "La gendarmería nacional asegura el mantenimiento del orden público y la seguridad de las personas, principalmente en las zonas rurales y periurbanas. Depende del Ministerio del Interior.", choices: [{ id: 'a' as const, text: "Garantizar la seguridad de las personas y mantener el orden, principalmente en zona rural" }, { id: 'b' as const, text: "Gestionar los impuestos de los ciudadanos" }, { id: 'c' as const, text: "Juzgar a las personas acusadas de crímenes" }, { id: 'd' as const, text: "Redactar las leyes" }] },
  { textFr: "Quel est le rôle de la police ?", lang: 'es' as const, text: "¿Cuál es el papel de la policía?", explanation: "La policía nacional asegura el mantenimiento del orden público y la seguridad de las personas, principalmente en zona urbana. Vela por el cumplimiento de las leyes y protege a los ciudadanos.", choices: [{ id: 'a' as const, text: "Garantizar la seguridad de las personas y mantener el orden público" }, { id: 'b' as const, text: "Votar las leyes en el Parlamento" }, { id: 'c' as const, text: "Recaudar los impuestos" }, { id: 'd' as const, text: "Dirigir los hospitales" }] },
  { textFr: "Qu'est-ce qu'une infraction ?", lang: 'es' as const, text: "¿Qué es una infracción?", explanation: "Una infracción es un comportamiento prohibido por la ley y castigado con sanciones penales. Existen tres categorías de infracciones en Francia: las contravenciones, los delitos y los crímenes, clasificados por orden de gravedad.", choices: [{ id: 'a' as const, text: "Un comportamiento prohibido por la ley y castigado con sanciones penales" }, { id: 'b' as const, text: "Una regla de cortesía no respetada" }, { id: 'c' as const, text: "Un desacuerdo entre dos personas" }, { id: 'd' as const, text: "Una opinión política controvertida" }] },
  { textFr: "Comment peut-on réduire ses déchets ?", lang: 'es' as const, text: "¿Cómo se pueden reducir los residuos?", explanation: "Se pueden reducir los residuos separándolos, reciclando, compostando, evitando el desperdicio alimentario y eligiendo productos con menos envases. La separación selectiva es un gesto ciudadano esencial.", choices: [{ id: 'a' as const, text: "Separando, reciclando y reduciendo el desperdicio" }, { id: 'b' as const, text: "Tirando todo en el mismo contenedor" }, { id: 'c' as const, text: "Quemando los residuos en el jardín" }, { id: 'd' as const, text: "Depositándolos en la naturaleza" }] },
  { textFr: "Déposer une machine à laver cassée sur le trottoir est :", lang: 'es' as const, text: "Dejar una lavadora rota en la acera es:", explanation: "Dejar un objeto voluminoso en la acera está prohibido y constituye un vertido ilegal sancionable con multa. Hay que llevar los objetos voluminosos al punto limpio o solicitar el servicio de recogida del ayuntamiento.", choices: [{ id: 'a' as const, text: "Prohibido y sancionable con multa" }, { id: 'b' as const, text: "Permitido si es de noche" }, { id: 'c' as const, text: "Permitido en las grandes ciudades" }, { id: 'd' as const, text: "Permitido si se deja una nota de disculpa" }] },
  { textFr: "En quoi consiste la traite des êtres humains ?", lang: 'es' as const, text: "¿En qué consiste la trata de seres humanos?", explanation: "La trata de seres humanos consiste en reclutar, transportar o alojar a una persona con fines de explotación (trabajo forzado, explotación sexual, etc.). Es un crimen severamente castigado por la ley francesa.", choices: [{ id: 'a' as const, text: "Explotar a personas con fines de trabajo forzado, explotación sexual u otros" }, { id: 'b' as const, text: "Hacer comercio internacional de mercancías" }, { id: 'c' as const, text: "Transportar personas de un país a otro legalmente" }, { id: 'd' as const, text: "Contratar trabajadores extranjeros con un contrato de trabajo" }] },
  { textFr: "Que doit faire une victime de violences ?", lang: 'es' as const, text: "¿Qué debe hacer una víctima de violencia?", explanation: "Una víctima de violencia debe presentar una denuncia ante la policía o la gendarmería y, si es necesario, llamar al 17 (policía de socorro) o al 3919 (violencia conyugal). También puede acudir a urgencias para que constaten sus lesiones.", choices: [{ id: 'a' as const, text: "Presentar una denuncia ante la policía o la gendarmería" }, { id: 'b' as const, text: "No hacer nada y esperar a que pase" }, { id: 'c' as const, text: "Vengarse por su cuenta" }, { id: 'd' as const, text: "Abandonar el país" }] },
  { textFr: "Quelle est l'infraction la plus grave ?", lang: 'es' as const, text: "¿Cuál es la infracción más grave?", explanation: "El crimen es la infracción más grave en el derecho penal francés. Es juzgado por el tribunal de lo criminal y puede ser castigado con reclusión criminal que puede llegar hasta la perpetuidad.", choices: [{ id: 'a' as const, text: "El crimen" }, { id: 'b' as const, text: "El delito" }, { id: 'c' as const, text: "La contravención" }, { id: 'd' as const, text: "La infracción menor" }] },
  { textFr: "À quelle liberté la PMA fait-elle référence ?", lang: 'es' as const, text: "¿A qué libertad hace referencia la PMA?", explanation: "La procreación médicamente asistida (PMA) hace referencia a la libertad de disponer de su propio cuerpo. Desde la ley de bioética de 2021, la PMA está abierta a todas las mujeres en Francia.", choices: [{ id: 'a' as const, text: "La libertad de disponer de su propio cuerpo" }, { id: 'b' as const, text: "La libertad de expresión" }, { id: 'c' as const, text: "La libertad de circulación" }, { id: 'd' as const, text: "La libertad de prensa" }] },
  { textFr: "Au nom de quoi l'État justifie-t-il la restriction des droits ?", lang: 'es' as const, text: "¿En nombre de qué justifica el Estado la restricción de derechos?", explanation: "El Estado puede restringir ciertos derechos en nombre del interés general y del orden público. Estas restricciones deben estar previstas por la ley y ser proporcionadas al objetivo perseguido.", choices: [{ id: 'a' as const, text: "En nombre del interés general y del orden público" }, { id: 'b' as const, text: "En nombre del Presidente de la República" }, { id: 'c' as const, text: "En nombre de los partidos políticos" }, { id: 'd' as const, text: "En nombre de las empresas privadas" }] },
  { textFr: "Concernant le droit de se marier, quelle proposition est correcte ?", lang: 'es' as const, text: "Respecto al derecho a casarse, ¿qué afirmación es correcta?", explanation: "En Francia, toda persona mayor de edad tiene derecho a casarse libremente, incluido con una persona del mismo sexo desde la ley del 17 de mayo de 2013. El matrimonio forzado está prohibido.", choices: [{ id: 'a' as const, text: "Toda persona mayor de edad puede casarse libremente, incluido con una persona del mismo sexo" }, { id: 'b' as const, text: "El matrimonio solo es posible entre un hombre y una mujer" }, { id: 'c' as const, text: "El matrimonio requiere la autorización de los padres, incluso para los mayores de edad" }, { id: 'd' as const, text: "El matrimonio solo es posible a partir de los 21 años" }] },
  { textFr: "Laquelle de ces citations est inscrite dans la Déclaration des droits de l'homme et du citoyen de 1789 ?", lang: 'es' as const, text: "¿Cuál de estas citas está inscrita en la Declaración de los Derechos del Hombre y del Ciudadano de 1789?", explanation: "El artículo 1 de la Declaración de los Derechos del Hombre y del Ciudadano de 1789 afirma que \"Los hombres nacen y permanecen libres e iguales en derechos\". Es uno de los principios fundadores de la República Francesa.", choices: [{ id: 'a' as const, text: "Los hombres nacen y permanecen libres e iguales en derechos" }, { id: 'b' as const, text: "Francia es una monarquía constitucional" }, { id: 'c' as const, text: "El trabajo es obligatorio para todos los ciudadanos" }, { id: 'd' as const, text: "La religión católica es la religión oficial de Francia" }] },
  { textFr: "Le recours à l'avortement est-il autorisé ?", lang: 'es' as const, text: "¿Está autorizado el recurso al aborto?", explanation: "Sí, el recurso al aborto está autorizado en Francia. La interrupción voluntaria del embarazo (IVE) es un derecho garantizado por la ley, realizable hasta las 14 semanas de embarazo. Este derecho fue constitucionalizado en 2024.", choices: [{ id: 'a' as const, text: "Sí, es un derecho garantizado por la ley" }, { id: 'b' as const, text: "No, está totalmente prohibido" }, { id: 'c' as const, text: "Únicamente en caso de peligro para la madre" }, { id: 'd' as const, text: "Solo con la autorización de un juez" }] },
  { textFr: "Que contient la Constitution ?", lang: 'es' as const, text: "¿Qué contiene la Constitución?", explanation: "La Constitución contiene las reglas fundamentales de organización del Estado, la distribución de poderes y los derechos y libertades fundamentales de los ciudadanos. Es la norma jurídica suprema en Francia.", choices: [{ id: 'a' as const, text: "Las reglas de organización del Estado y los derechos fundamentales de los ciudadanos" }, { id: 'b' as const, text: "Únicamente las leyes penales" }, { id: 'c' as const, text: "Las reglas del código de circulación" }, { id: 'd' as const, text: "La lista de impuestos a pagar" }] },
  { textFr: "Que garantit la liberté de la presse ?", lang: 'es' as const, text: "¿Qué garantiza la libertad de prensa?", explanation: "La libertad de prensa garantiza el derecho a informar y a ser informado libremente. Está consagrada por la ley del 29 de julio de 1881 y constituye un pilar de la democracia francesa.", choices: [{ id: 'a' as const, text: "El derecho a informar y a ser informado libremente" }, { id: 'b' as const, text: "El derecho a publicar noticias falsas" }, { id: 'c' as const, text: "El derecho a difamar a cualquier persona pública" }, { id: 'd' as const, text: "El derecho a no respetar la vida privada" }] },
  { textFr: "Que prévoit la Charte de l'environnement ?", lang: 'es' as const, text: "¿Qué prevé la Carta del Medio Ambiente?", explanation: "La Carta del Medio Ambiente, integrada en el bloque de constitucionalidad en 2005, prevé que cada persona tiene derecho a vivir en un medio ambiente equilibrado y respetuoso con la salud, y el deber de preservar el medio ambiente.", choices: [{ id: 'a' as const, text: "El derecho a vivir en un medio ambiente sano y el deber de preservarlo" }, { id: 'b' as const, text: "La prohibición total de la industria en Francia" }, { id: 'c' as const, text: "El derecho a contaminar si se paga un impuesto" }, { id: 'd' as const, text: "La obligación de vivir en el campo" }] },
  { textFr: "Que signifie la dignité humaine ?", lang: 'es' as const, text: "¿Qué significa la dignidad humana?", explanation: "La dignidad humana significa que todo ser humano tiene un valor intrínseco que debe ser respetado. Este principio prohíbe los tratos degradantes, inhumanos o crueles y constituye un derecho fundamental.", choices: [{ id: 'a' as const, text: "Que todo ser humano tiene un valor que debe ser respetado y protegido" }, { id: 'b' as const, text: "Que solo los ciudadanos franceses merecen respeto" }, { id: 'c' as const, text: "Que la dignidad depende de la riqueza de una persona" }, { id: 'd' as const, text: "Que la dignidad es un privilegio otorgado por el Estado" }] },
  { textFr: "Que signifie le droit de manifester ?", lang: 'es' as const, text: "¿Qué significa el derecho a manifestarse?", explanation: "El derecho a manifestarse permite a los ciudadanos reunirse pacíficamente en el espacio público para expresar una opinión o reivindicar un derecho. Está regulado por la ley y generalmente requiere una declaración previa en la prefectura.", choices: [{ id: 'a' as const, text: "El derecho a reunirse pacíficamente para expresar una opinión" }, { id: 'b' as const, text: "El derecho a bloquear carreteras sin autorización" }, { id: 'c' as const, text: "El derecho a destruir bienes públicos" }, { id: 'd' as const, text: "El derecho a recurrir a la violencia para defender sus ideas" }] },
  { textFr: "Que signifie PMA ?", lang: 'es' as const, text: "¿Qué significa PMA?", explanation: "PMA significa Procreación Médicamente Asistida. Agrupa las técnicas médicas que permiten concebir un hijo fuera del proceso natural. Desde 2021, la PMA está abierta a todas las mujeres en Francia.", choices: [{ id: 'a' as const, text: "Procreación Médicamente Asistida" }, { id: 'b' as const, text: "Protección Médica Avanzada" }, { id: 'c' as const, text: "Prestación Mensual Automática" }, { id: 'd' as const, text: "Programa Médico de Acompañamiento" }] },
  { textFr: "Quel texte est le plus difficile à modifier ?", lang: 'es' as const, text: "¿Qué texto es el más difícil de modificar?", explanation: "La Constitución es el texto más difícil de modificar. Su revisión requiere ya sea un voto del Congreso por mayoría de 3/5, o un referéndum. Es la norma suprema del orden jurídico francés.", choices: [{ id: 'a' as const, text: "La Constitución" }, { id: 'b' as const, text: "Una ley ordinaria" }, { id: 'c' as const, text: "Un decreto" }, { id: 'd' as const, text: "Una ordenanza municipal" }] },
  { textFr: "Quelle liberté permet à une personne de croire en la religion de son choix ?", lang: 'es' as const, text: "¿Qué libertad permite a una persona creer en la religión de su elección?", explanation: "La libertad de conciencia y la libertad de culto permiten a cada persona creer en la religión de su elección o no creer en ninguna. Estas libertades están garantizadas por la ley de 1905 y la Constitución.", choices: [{ id: 'a' as const, text: "La libertad de conciencia y de culto" }, { id: 'b' as const, text: "La libertad de prensa" }, { id: 'c' as const, text: "La libertad de empresa" }, { id: 'd' as const, text: "La libertad de circulación" }] },
  { textFr: "Qu'est-ce que le droit de grève ?", lang: 'es' as const, text: "¿Qué es el derecho de huelga?", explanation: "El derecho de huelga es el derecho de los trabajadores a cesar colectivamente el trabajo para defender sus reivindicaciones profesionales. Está reconocido por el preámbulo de la Constitución de 1946, integrado en el bloque de constitucionalidad.", choices: [{ id: 'a' as const, text: "El derecho a cesar colectivamente el trabajo para defender sus reivindicaciones profesionales" }, { id: 'b' as const, text: "El derecho a no trabajar nunca" }, { id: 'c' as const, text: "El derecho a destruir su lugar de trabajo" }, { id: 'd' as const, text: "El derecho a dejar definitivamente su empleo sin preaviso" }] },
  { textFr: "Qu'est-ce que la Constitution ?", lang: 'es' as const, text: "¿Qué es la Constitución?", explanation: "La Constitución es el texto jurídico supremo que organiza los poderes del Estado y garantiza los derechos fundamentales de los ciudadanos. La Constitución actual de Francia data del 4 de octubre de 1958.", choices: [{ id: 'a' as const, text: "El texto jurídico supremo que organiza los poderes del Estado" }, { id: 'b' as const, text: "Un compendio de leyes penales" }, { id: 'c' as const, text: "El reglamento interno de la Asamblea Nacional" }, { id: 'd' as const, text: "Un tratado internacional firmado por Francia" }] },
  { textFr: "Qui peut demander à avorter ?", lang: 'es' as const, text: "¿Quién puede solicitar abortar?", explanation: "Toda mujer embarazada que no desee continuar su embarazo puede solicitar abortar, dentro de los plazos previstos por la ley (14 semanas de embarazo). Las menores de edad deben estar acompañadas por un adulto de su elección.", choices: [{ id: 'a' as const, text: "Toda mujer embarazada, dentro de los plazos previstos por la ley" }, { id: 'b' as const, text: "Únicamente las mujeres casadas" }, { id: 'c' as const, text: "Únicamente las mujeres mayores de 25 años" }, { id: 'd' as const, text: "Únicamente por decisión de un juez" }] },
  { textFr: "Une femme majeure de nationalité française a-t-elle le droit de voter aux élections ?", lang: 'es' as const, text: "¿Tiene derecho a votar en las elecciones una mujer mayor de edad de nacionalidad francesa?", explanation: "Sí, toda mujer mayor de edad de nacionalidad francesa tiene derecho a votar. El derecho al voto de las mujeres fue concedido en 1944 en Francia. El sufragio es universal y no hace ninguna distinción de sexo.", choices: [{ id: 'a' as const, text: "Sí, todas las mujeres mayores de edad de nacionalidad francesa tienen derecho a votar" }, { id: 'b' as const, text: "No, solo los hombres pueden votar" }, { id: 'c' as const, text: "Solo en las elecciones municipales" }, { id: 'd' as const, text: "Solo si tienen empleo" }] },
  { textFr: "Concernant l'utilisation des réseaux sociaux, quelle proposition est correcte ?", lang: 'es' as const, text: "Respecto al uso de las redes sociales, ¿qué afirmación es correcta?", explanation: "El uso de las redes sociales está sujeto al respeto de la ley. Los comentarios racistas, de odio, difamatorios o que inciten a la violencia están prohibidos en línea como en la vida real.", choices: [{ id: 'a' as const, text: "La ley también se aplica en las redes sociales: los comentarios de odio o difamatorios están prohibidos" }, { id: 'b' as const, text: "Se puede decir lo que se quiera en las redes sociales sin consecuencias" }, { id: 'c' as const, text: "Las redes sociales no están sujetas a la ley francesa" }, { id: 'd' as const, text: "Solo las cuentas verificadas deben respetar la ley" }] },
  { textFr: "Jeter un mégot par terre est :", lang: 'es' as const, text: "Tirar una colilla al suelo es:", explanation: "Tirar una colilla de cigarrillo al suelo es una infracción sancionable con una multa de 135 euros. Es un gesto contaminante que perjudica el medio ambiente y la limpieza de los espacios públicos.", choices: [{ id: 'a' as const, text: "Prohibido y sancionable con multa" }, { id: 'b' as const, text: "Permitido en los espacios públicos" }, { id: 'c' as const, text: "Tolerado si se está al aire libre" }, { id: 'd' as const, text: "Prohibido únicamente en los parques" }] },
  { textFr: "L'État peut-il limiter les droits et libertés ?", lang: 'es' as const, text: "¿Puede el Estado limitar los derechos y libertades?", explanation: "Sí, el Estado puede limitar los derechos y libertades, pero únicamente en las condiciones previstas por la ley, por razones de orden público, seguridad o para proteger los derechos de los demás. Estas limitaciones deben ser proporcionadas.", choices: [{ id: 'a' as const, text: "Sí, en las condiciones previstas por la ley y de manera proporcionada" }, { id: 'b' as const, text: "No, nunca, las libertades son absolutas" }, { id: 'c' as const, text: "Sí, sin ningún límite" }, { id: 'd' as const, text: "Solo en tiempo de guerra" }] },
  { textFr: "Parmi ces actions, laquelle permet d'adopter une attitude respectueuse de l'environnement ?", lang: 'es' as const, text: "Entre estas acciones, ¿cuál permite adoptar una actitud respetuosa con el medio ambiente?", explanation: "Separar los residuos es un gesto sencillo y concreto que permite proteger el medio ambiente. La separación selectiva facilita el reciclaje y reduce la cantidad de residuos enviados a vertederos o incinerados.", choices: [{ id: 'a' as const, text: "Separar los residuos" }, { id: 'b' as const, text: "Tirar los residuos en la naturaleza" }, { id: 'c' as const, text: "Dejar el agua corriendo permanentemente" }, { id: 'd' as const, text: "Usar el coche para todos los trayectos" }] },
  { textFr: "Quelle proposition constitue une obligation ?", lang: 'es' as const, text: "¿Qué proposición constituye una obligación?", explanation: "El respeto de la ley es una obligación para toda persona que resida en Francia, sea cual sea su nacionalidad. Nadie puede ignorar la ley y cada persona debe cumplirla.", choices: [{ id: 'a' as const, text: "Respetar la ley" }, { id: 'b' as const, text: "Votar en las elecciones" }, { id: 'c' as const, text: "Afiliarse a un partido político" }, { id: 'd' as const, text: "Hacer voluntariado" }] },
  { textFr: "Pour quel motif peut-on limiter la liberté d'expression ?", lang: 'es' as const, text: "¿Por qué motivo se puede limitar la libertad de expresión?", explanation: "La libertad de expresión puede ser limitada para prevenir atentados contra el orden público, proteger la reputación o los derechos de los demás, y prohibir los comentarios de odio, racistas o difamatorios.", choices: [{ id: 'a' as const, text: "Para proteger el orden público y los derechos de los demás" }, { id: 'b' as const, text: "Para impedir toda crítica al gobierno" }, { id: 'c' as const, text: "Para prohibir las opiniones religiosas" }, { id: 'd' as const, text: "Nunca se puede limitar la libertad de expresión" }] },
  { textFr: "Pourquoi doit-on trier ses déchets ?", lang: 'es' as const, text: "¿Por qué hay que separar los residuos?", explanation: "La separación de residuos es necesaria para permitir el reciclaje, reducir la contaminación y preservar los recursos naturales. Es una obligación ciudadana que contribuye a la protección del medio ambiente.", choices: [{ id: 'a' as const, text: "Para permitir el reciclaje y proteger el medio ambiente" }, { id: 'b' as const, text: "Únicamente para evitar una multa" }, { id: 'c' as const, text: "No es obligatorio" }, { id: 'd' as const, text: "Únicamente en las grandes ciudades" }] },
  { textFr: "Que doit-on faire face aux ordres des policiers ou gendarmes ?", lang: 'es' as const, text: "¿Qué se debe hacer ante las órdenes de los policías o gendarmes?", explanation: "Toda persona debe obedecer las órdenes legítimas de los policías y gendarmes. La negativa a obedecer es una infracción penal. En caso de desacuerdo, se puede impugnar posteriormente por vía legal.", choices: [{ id: 'a' as const, text: "Obedecer sus órdenes legítimas" }, { id: 'b' as const, text: "Ignorarlos sistemáticamente" }, { id: 'c' as const, text: "Resistir físicamente" }, { id: 'd' as const, text: "Huir sin responder" }] },
  { textFr: "Quel est un exemple d'assistance à personne en danger ?", lang: 'es' as const, text: "¿Cuál es un ejemplo de asistencia a persona en peligro?", explanation: "Llamar a los servicios de emergencia cuando se es testigo de un accidente es un ejemplo de asistencia a persona en peligro. En Francia, no prestar asistencia a una persona en peligro es un delito castigado por la ley.", choices: [{ id: 'a' as const, text: "Llamar a los servicios de emergencia cuando se es testigo de un accidente" }, { id: 'b' as const, text: "Grabar la escena sin intervenir" }, { id: 'c' as const, text: "Alejarse rápidamente del lugar" }, { id: 'd' as const, text: "Esperar a que la policía llegue sola" }] },
  { textFr: "Quel exemple illustre une limitation de liberté pour protéger l'intérêt général ?", lang: 'es' as const, text: "¿Qué ejemplo ilustra una limitación de libertad para proteger el interés general?", explanation: "La prohibición de fumar en lugares públicos cerrados es un ejemplo de limitación de la libertad individual para proteger la salud pública y el interés general. Esta medida protege a los no fumadores del tabaquismo pasivo.", choices: [{ id: 'a' as const, text: "La prohibición de fumar en lugares públicos cerrados" }, { id: 'b' as const, text: "La prohibición de votar" }, { id: 'c' as const, text: "La prohibición de hablar en público" }, { id: 'd' as const, text: "La prohibición de circular libremente" }] },
  { textFr: "Quelle est l'attitude à avoir lorsqu'on est témoin de violences ?", lang: 'es' as const, text: "¿Cuál es la actitud que se debe tener cuando se es testigo de violencia?", explanation: "Cuando se es testigo de violencia, se deben avisar a los servicios de emergencia (policía, bomberos, SAMU) y, si es posible, prestar asistencia a la víctima sin ponerse en peligro. No actuar puede constituir un delito de no asistencia a persona en peligro.", choices: [{ id: 'a' as const, text: "Avisar a los servicios de emergencia y, si es posible, prestar asistencia a la víctima" }, { id: 'b' as const, text: "Grabar la escena y difundirla en las redes sociales" }, { id: 'c' as const, text: "No hacer nada porque no nos concierne" }, { id: 'd' as const, text: "Irse inmediatamente para no verse implicado" }] },
  { textFr: "Quelle obligation concerne toutes les personnes résidant en France quelle que soit leur nationalité ?", lang: 'es' as const, text: "¿Qué obligación concierne a todas las personas que residen en Francia independientemente de su nacionalidad?", explanation: "El respeto de la ley francesa es una obligación que concierne a todas las personas que residen en Francia, sea cual sea su nacionalidad. Se presume que nadie desconoce la ley en el territorio francés.", choices: [{ id: 'a' as const, text: "El respeto de la ley francesa" }, { id: 'b' as const, text: "El voto en las elecciones presidenciales" }, { id: 'c' as const, text: "El servicio militar" }, { id: 'd' as const, text: "La afiliación a un sindicato" }] },
  { textFr: "Quelle proposition représente un exemple de crime ?", lang: 'es' as const, text: "¿Qué proposición representa un ejemplo de crimen?", explanation: "El asesinato es un ejemplo de crimen, es decir, la infracción más grave en el derecho penal francés. Los crímenes son juzgados por el tribunal de lo criminal y castigados con penas de reclusión criminal.", choices: [{ id: 'a' as const, text: "El asesinato" }, { id: 'b' as const, text: "Un exceso de velocidad" }, { id: 'c' as const, text: "El ruido nocturno" }, { id: 'd' as const, text: "Un estacionamiento prohibido" }] },
  { textFr: "Quelle proposition représente un exemple de délit ?", lang: 'es' as const, text: "¿Qué proposición representa un ejemplo de delito?", explanation: "El robo es un ejemplo de delito. Un delito es una infracción de gravedad intermedia, juzgada por el tribunal correccional. Se castiga con penas de multa y/o prisión de hasta 10 años.", choices: [{ id: 'a' as const, text: "El robo" }, { id: 'b' as const, text: "Un exceso de velocidad de 5 km/h" }, { id: 'c' as const, text: "El ruido nocturno" }, { id: 'd' as const, text: "El homicidio premeditado" }] },
  { textFr: "Qui veille au maintien de l'ordre public ?", lang: 'es' as const, text: "¿Quién vela por el mantenimiento del orden público?", explanation: "La policía y la gendarmería velan por el mantenimiento del orden público en Francia. La policía interviene principalmente en zona urbana y la gendarmería en zona rural y periurbana.", choices: [{ id: 'a' as const, text: "La policía y la gendarmería" }, { id: 'b' as const, text: "Los propios ciudadanos" }, { id: 'c' as const, text: "Únicamente los alcaldes" }, { id: 'd' as const, text: "Los abogados" }] },
  { textFr: "S'agissant des déchets, quelle proposition est correcte ?", lang: 'es' as const, text: "Respecto a los residuos, ¿qué afirmación es correcta?", explanation: "La separación de residuos es una obligación legal en Francia. Cada ciudadano debe separar sus residuos según las instrucciones de su municipio para facilitar el reciclaje y proteger el medio ambiente.", choices: [{ id: 'a' as const, text: "La separación de residuos es una obligación para proteger el medio ambiente" }, { id: 'b' as const, text: "Se pueden tirar todos los residuos en el mismo contenedor" }, { id: 'c' as const, text: "La separación de residuos es opcional" }, { id: 'd' as const, text: "Solo las empresas deben separar sus residuos" }] },
  { textFr: "À quoi sert le droit de grève ?", lang: 'es' as const, text: "¿Para qué sirve el derecho de huelga?", explanation: "El derecho de huelga permite a los trabajadores cesar colectivamente el trabajo para defender sus reivindicaciones profesionales (salarios, condiciones de trabajo, etc.). Está garantizado por el preámbulo de la Constitución de 1946.", choices: [{ id: 'a' as const, text: "Para permitir a los trabajadores defender colectivamente sus reivindicaciones profesionales" }, { id: 'b' as const, text: "Para autorizar a los trabajadores a no trabajar nunca más" }, { id: 'c' as const, text: "Para permitir a los empleadores despedir a los trabajadores descontentos" }, { id: 'd' as const, text: "Para obligar al Estado a aumentar los salarios" }] },
  { textFr: "L'article 4 de la Déclaration des droits de l'homme et du citoyen affirme que « la liberté consiste à pouvoir faire tout ce qui ne nuit pas à autrui ». Qu'est-ce que cela signifie ?", lang: 'es' as const, text: "El artículo 4 de la Declaración de los Derechos del Hombre y del Ciudadano afirma que \"la libertad consiste en poder hacer todo lo que no perjudique a los demás\". ¿Qué significa esto?", explanation: "Esto significa que cada persona es libre de actuar siempre que no atente contra los derechos y libertades de los demás. La libertad individual termina donde comienza la de los demás.", choices: [{ id: 'a' as const, text: "Cada persona es libre de actuar siempre que no atente contra los derechos de los demás" }, { id: 'b' as const, text: "Se puede hacer absolutamente todo lo que se quiera" }, { id: 'c' as const, text: "La libertad no existe en Francia" }, { id: 'd' as const, text: "Solo el Estado puede decidir lo que está permitido" }] },
  { textFr: "Que dit l'article 1er de la Constitution française ?", lang: 'es' as const, text: "¿Qué dice el artículo 1 de la Constitución francesa?", explanation: "El artículo 1 de la Constitución establece que Francia es una República indivisible, laica, democrática y social. Asegura la igualdad ante la ley de todos los ciudadanos sin distinción de origen, raza o religión.", choices: [{ id: 'a' as const, text: "Francia es una República indivisible, laica, democrática y social" }, { id: 'b' as const, text: "Francia es una monarquía constitucional" }, { id: 'c' as const, text: "El Presidente es elegido por 7 años" }, { id: 'd' as const, text: "La religión católica es la religión de Estado" }] },
  { textFr: "Que permet la liberté de circulation ?", lang: 'es' as const, text: "¿Qué permite la libertad de circulación?", explanation: "La libertad de circulación permite a toda persona desplazarse libremente por el territorio francés y salir de él. Está garantizada por la Constitución y por los tratados europeos para los ciudadanos de la UE.", choices: [{ id: 'a' as const, text: "Desplazarse libremente por el territorio francés" }, { id: 'b' as const, text: "Conducir sin permiso" }, { id: 'c' as const, text: "No respetar el código de circulación" }, { id: 'd' as const, text: "Circular únicamente en su municipio de residencia" }] },
  { textFr: "Que signifie être citoyen d'un État ?", lang: 'es' as const, text: "¿Qué significa ser ciudadano de un Estado?", explanation: "Ser ciudadano de un Estado significa tener derechos (voto, protección, libertades) y deberes (respeto de la ley, pago de impuestos, defensa del país) hacia ese Estado. La ciudadanía está vinculada a la nacionalidad.", choices: [{ id: 'a' as const, text: "Tener derechos y deberes hacia ese Estado" }, { id: 'b' as const, text: "Tener únicamente derechos sin ningún deber" }, { id: 'c' as const, text: "Residir en el país sin ninguna obligación" }, { id: 'd' as const, text: "Estar obligado a trabajar para el Estado" }] },
  { textFr: "Que sont les droits fondamentaux ?", lang: 'es' as const, text: "¿Qué son los derechos fundamentales?", explanation: "Los derechos fundamentales son los derechos esenciales garantizados a cada individuo, como la libertad, la igualdad, la dignidad y la seguridad. Están protegidos por la Constitución y los textos internacionales.", choices: [{ id: 'a' as const, text: "Los derechos esenciales garantizados a cada individuo, como la libertad y la igualdad" }, { id: 'b' as const, text: "Los derechos reservados a los funcionarios" }, { id: 'c' as const, text: "Los derechos otorgados únicamente por el Presidente" }, { id: 'd' as const, text: "Los derechos que cambian en cada elección" }] },
  { textFr: "Quel droit protège une personne contre une arrestation arbitraire ?", lang: 'es' as const, text: "¿Qué derecho protege a una persona contra una detención arbitraria?", explanation: "El derecho a la seguridad protege a toda persona contra las detenciones y encarcelamientos arbitrarios. Está garantizado por la Declaración de los Derechos del Hombre y del Ciudadano de 1789 y por el Convenio Europeo de Derechos Humanos.", choices: [{ id: 'a' as const, text: "El derecho a la seguridad" }, { id: 'b' as const, text: "El derecho al voto" }, { id: 'c' as const, text: "El derecho de huelga" }, { id: 'd' as const, text: "El derecho a la propiedad" }] },
  { textFr: "Quel texte affirme que tous les hommes naissent libres et égaux en droits ?", lang: 'es' as const, text: "¿Qué texto afirma que todos los hombres nacen libres e iguales en derechos?", explanation: "La Declaración de los Derechos del Hombre y del Ciudadano de 1789 afirma en su artículo 1 que \"Los hombres nacen y permanecen libres e iguales en derechos\". Es un texto fundador de los derechos humanos.", choices: [{ id: 'a' as const, text: "La Declaración de los Derechos del Hombre y del Ciudadano de 1789" }, { id: 'b' as const, text: "El Código civil de 1804" }, { id: 'c' as const, text: "El Tratado de Roma de 1957" }, { id: 'd' as const, text: "La Carta de las Naciones Unidas de 1945" }] },
  { textFr: "Quelle situation est une atteinte à la dignité humaine ?", lang: 'es' as const, text: "¿Qué situación es un atentado contra la dignidad humana?", explanation: "La esclavitud, la tortura y los tratos inhumanos o degradantes son atentados contra la dignidad humana. La dignidad humana es un principio fundamental protegido por la Constitución y los convenios internacionales.", choices: [{ id: 'a' as const, text: "La esclavitud y la tortura" }, { id: 'b' as const, text: "El derecho al voto" }, { id: 'c' as const, text: "El trabajo asalariado" }, { id: 'd' as const, text: "La educación obligatoria" }] },
  { textFr: "Suite à une interpellation par la police, il est possible de :", lang: 'es' as const, text: "Tras una detención por la policía, es posible:", explanation: "Tras una detención, es posible ser puesto bajo custodia policial por un periodo inicial de 24 horas. La persona conserva el derecho a consultar un abogado y a ser informada de sus derechos.", choices: [{ id: 'a' as const, text: "Ser puesto bajo custodia policial y consultar un abogado" }, { id: 'b' as const, text: "Ser encarcelado inmediatamente sin juicio" }, { id: 'c' as const, text: "Negarse a dar su identidad" }, { id: 'd' as const, text: "Abandonar libremente la comisaría en cualquier momento" }] },
  { textFr: "Tous les citoyens français ont-ils une religion ?", lang: 'es' as const, text: "¿Tienen todos los ciudadanos franceses una religión?", explanation: "No, no todos los ciudadanos franceses tienen necesariamente una religión. Francia es un Estado laico que garantiza la libertad de conciencia: cada persona es libre de creer o de no creer.", choices: [{ id: 'a' as const, text: "No, cada persona es libre de creer o de no creer" }, { id: 'b' as const, text: "Sí, todos los franceses deben tener una religión" }, { id: 'c' as const, text: "Sí, la religión católica es obligatoria" }, { id: 'd' as const, text: "No, la religión está prohibida en Francia" }] },
  { textFr: "À quel âge est la majorité numérique en France ?", lang: 'es' as const, text: "¿A qué edad es la mayoría digital en Francia?", explanation: "La mayoría digital en Francia está fijada en 15 años. Por debajo de esta edad, la inscripción en redes sociales requiere el consentimiento de los padres. Esta medida tiene como objetivo proteger a los menores en línea.", choices: [{ id: 'a' as const, text: "15 años" }, { id: 'b' as const, text: "13 años" }, { id: 'c' as const, text: "16 años" }, { id: 'd' as const, text: "18 años" }] },
  { textFr: "Dans lequel de ces endroits est-on autorisé à fumer ?", lang: 'es' as const, text: "¿En cuál de estos lugares está permitido fumar?", explanation: "Está permitido fumar en espacios privados como el propio domicilio. En cambio, está prohibido fumar en lugares públicos cerrados y cubiertos (restaurantes, bares, estaciones, etc.) desde la ley de 2007.", choices: [{ id: 'a' as const, text: "En casa, en un espacio privado" }, { id: 'b' as const, text: "En un restaurante" }, { id: 'c' as const, text: "En un hospital" }, { id: 'd' as const, text: "En una escuela" }] },
  { textFr: "En France, la conduite sans permis d'une moto est :", lang: 'es' as const, text: "En Francia, conducir una moto sin permiso es:", explanation: "Conducir sin permiso es un delito en Francia, sancionable con un año de prisión y 15.000 euros de multa. El permiso de conducir es obligatorio para conducir cualquier vehículo motorizado.", choices: [{ id: 'a' as const, text: "Un delito sancionable con multa y prisión" }, { id: 'b' as const, text: "Permitido si la moto es de pequeña cilindrada" }, { id: 'c' as const, text: "Una simple contravención" }, { id: 'd' as const, text: "Permitido para trayectos cortos" }] },
  { textFr: "En quoi consiste le devoir de solidarité ?", lang: 'es' as const, text: "¿En qué consiste el deber de solidaridad?", explanation: "El deber de solidaridad consiste en contribuir a la cohesión social, especialmente mediante el pago de impuestos y cotizaciones sociales que financian los servicios públicos y la protección social para todos.", choices: [{ id: 'a' as const, text: "Contribuir a la cohesión social, especialmente mediante el pago de impuestos y cotizaciones" }, { id: 'b' as const, text: "Dar todo su dinero a las asociaciones" }, { id: 'c' as const, text: "No hacer nada y esperar la ayuda del Estado" }, { id: 'd' as const, text: "Ayudar únicamente a las personas de su familia" }] },
  { textFr: "Est-ce obligatoire de déclarer ses impôts chaque année en France ?", lang: 'es' as const, text: "¿Es obligatorio declarar los impuestos cada año en Francia?", explanation: "Sí, toda persona que reside en Francia y tiene ingresos está obligada a declarar sus impuestos cada año ante la administración fiscal. Es una obligación legal, incluso si no se paga impuesto.", choices: [{ id: 'a' as const, text: "Sí, es una obligación legal para toda persona que reside en Francia" }, { id: 'b' as const, text: "No, es opcional" }, { id: 'c' as const, text: "Solo si se gana más de 50.000 euros al año" }, { id: 'd' as const, text: "Solo para los ciudadanos franceses" }] },
  { textFr: "Est-il obligatoire de porter secours à une personne en danger ?", lang: 'es' as const, text: "¿Es obligatorio socorrer a una persona en peligro?", explanation: "Sí, en Francia, no prestar asistencia a una persona en peligro es un delito previsto por el artículo 223-6 del Código penal. Toda persona que sea testigo de un peligro debe actuar, como mínimo llamando a los servicios de emergencia.", choices: [{ id: 'a' as const, text: "Sí, la no asistencia a persona en peligro es un delito" }, { id: 'b' as const, text: "No, es una elección personal" }, { id: 'c' as const, text: "Únicamente si se es médico" }, { id: 'd' as const, text: "Únicamente si la persona es de nacionalidad francesa" }] },
  { textFr: "Être juré d'assises est :", lang: 'es' as const, text: "Ser jurado de lo criminal es:", explanation: "Ser jurado de lo criminal es un deber cívico obligatorio. Los jurados son elegidos por sorteo de las listas electorales y participan en el juicio de los crímenes más graves. Negarse sin motivo legítimo es sancionable con multa.", choices: [{ id: 'a' as const, text: "Un deber cívico obligatorio" }, { id: 'b' as const, text: "Una elección voluntaria" }, { id: 'c' as const, text: "Reservado a los abogados" }, { id: 'd' as const, text: "Prohibido para las mujeres" }] },
  { textFr: "La vente d'alcool en France est interdite aux personnes de moins de :", lang: 'es' as const, text: "La venta de alcohol en Francia está prohibida a las personas menores de:", explanation: "La venta de alcohol está prohibida a los menores de 18 años en Francia. Esta medida tiene como objetivo proteger la salud de los jóvenes. Los comerciantes pueden pedir un documento de identidad para verificar la edad.", choices: [{ id: 'a' as const, text: "18 años" }, { id: 'b' as const, text: "16 años" }, { id: 'c' as const, text: "21 años" }, { id: 'd' as const, text: "14 años" }] },
  { textFr: "Le non-respect du code de la route est :", lang: 'es' as const, text: "El incumplimiento del código de circulación es:", explanation: "El incumplimiento del código de circulación es una infracción que puede ser una contravención o un delito según la gravedad. Las sanciones van desde la multa hasta la retirada del permiso, e incluso la prisión.", choices: [{ id: 'a' as const, text: "Una infracción sancionable" }, { id: 'b' as const, text: "Tolerado si se es prudente" }, { id: 'c' as const, text: "Sin consecuencia jurídica" }, { id: 'd' as const, text: "Permitido en caso de emergencia personal" }] },
  { textFr: "Lequel de ces crimes ou délits peut entraîner la privation des droits civils et politiques par un juge ?", lang: 'es' as const, text: "¿Cuál de estos crímenes o delitos puede conllevar la privación de los derechos civiles y políticos por un juez?", explanation: "Ciertos crímenes o delitos graves, como la corrupción o los atentados contra los intereses fundamentales de la nación, pueden conllevar la privación de los derechos civiles y políticos (derecho al voto, elegibilidad) pronunciada por un juez.", choices: [{ id: 'a' as const, text: "Los crímenes y delitos graves como la corrupción" }, { id: 'b' as const, text: "Un exceso de velocidad" }, { id: 'c' as const, text: "El ruido nocturno" }, { id: 'd' as const, text: "El estacionamiento prohibido" }] },
  { textFr: "Pour obtenir une carte d'identité, il faut :", lang: 'es' as const, text: "Para obtener un documento de identidad, hay que:", explanation: "Para obtener un documento de identidad, hay que presentar un justificante de nacionalidad francesa, un justificante de domicilio, fotos de identidad y rellenar un formulario. La solicitud se realiza en el ayuntamiento o en línea mediante una presolicitud.", choices: [{ id: 'a' as const, text: "Presentar un justificante de nacionalidad, un justificante de domicilio y fotos de identidad" }, { id: 'b' as const, text: "Simplemente presentarse en el ayuntamiento sin documentos" }, { id: 'c' as const, text: "Pagar una suma de 500 euros" }, { id: 'd' as const, text: "Tener los antecedentes penales limpios" }] },
  { textFr: "Que doit faire un citoyen s'il est appelé à être juré dans un procès d'assises ?", lang: 'es' as const, text: "¿Qué debe hacer un ciudadano si es llamado a ser jurado en un juicio criminal?", explanation: "Un ciudadano llamado a ser jurado de lo criminal debe presentarse en el tribunal. Es un deber cívico obligatorio. Negarse sin motivo legítimo es sancionable con una multa de 3.750 euros.", choices: [{ id: 'a' as const, text: "Presentarse en el tribunal porque es un deber cívico obligatorio" }, { id: 'b' as const, text: "Ignorar la citación porque es opcional" }, { id: 'c' as const, text: "Enviar a otra persona en su lugar" }, { id: 'd' as const, text: "Pedir a un abogado que lo reemplace" }] },
  { textFr: "Quel est l'âge de la majorité civile en France ?", lang: 'es' as const, text: "¿Cuál es la edad de la mayoría civil en Francia?", explanation: "La mayoría civil en Francia está fijada en 18 años. A esta edad, una persona adquiere plena capacidad jurídica: puede votar, casarse sin autorización parental, firmar contratos, etc.", choices: [{ id: 'a' as const, text: "18 años" }, { id: 'b' as const, text: "16 años" }, { id: 'c' as const, text: "21 años" }, { id: 'd' as const, text: "15 años" }] },
  { textFr: "Quel est l'un des devoirs principaux d'un citoyen français ?", lang: 'es' as const, text: "¿Cuál es uno de los deberes principales de un ciudadano francés?", explanation: "El respeto de la ley es uno de los deberes principales de un ciudadano francés. Entre los demás deberes figuran el pago de impuestos, la participación en la defensa del país y el deber de votar.", choices: [{ id: 'a' as const, text: "Respetar la ley y pagar sus impuestos" }, { id: 'b' as const, text: "Afiliarse a un partido político" }, { id: 'c' as const, text: "Asistir a todas las sesiones del Parlamento" }, { id: 'd' as const, text: "Llevar un uniforme nacional" }] },
  { textFr: "Qu'est-ce que la citoyenneté numérique ?", lang: 'es' as const, text: "¿Qué es la ciudadanía digital?", explanation: "La ciudadanía digital designa el conjunto de derechos y deberes de los individuos en el uso de las tecnologías digitales. Implica un uso responsable de Internet y de las redes sociales, dentro del respeto a la ley.", choices: [{ id: 'a' as const, text: "El conjunto de derechos y deberes vinculados al uso responsable de lo digital" }, { id: 'b' as const, text: "El derecho a piratear sitios de Internet" }, { id: 'c' as const, text: "La obligación de tener una cuenta en las redes sociales" }, { id: 'd' as const, text: "El derecho a publicar anónimamente comentarios de odio" }] },
  { textFr: "Qu'est-ce que le devoir de mémoire ?", lang: 'es' as const, text: "¿Qué es el deber de memoria?", explanation: "El deber de memoria es la obligación moral de recordar los acontecimientos trágicos de la historia (guerras, genocidios, etc.) para evitar que se repitan. Se manifiesta a través de las conmemoraciones y la enseñanza de la historia.", choices: [{ id: 'a' as const, text: "La obligación moral de recordar los acontecimientos trágicos de la historia" }, { id: 'b' as const, text: "La obligación de memorizar la Constitución" }, { id: 'c' as const, text: "El deber de conocer a todos los presidentes de memoria" }, { id: 'd' as const, text: "La obligación de visitar todos los museos de Francia" }] },
  { textFr: "Une personne est privée de ses droits civils et politiques pendant 5 ans suite à une condamnation. Parmi ces propositions laquelle est correcte ?", lang: 'es' as const, text: "Una persona es privada de sus derechos civiles y políticos durante 5 años tras una condena. Entre estas proposiciones, ¿cuál es correcta?", explanation: "Cuando una persona es privada de sus derechos civiles y políticos por decisión judicial, no puede votar ni presentarse a una elección durante el periodo fijado por el juez.", choices: [{ id: 'a' as const, text: "No puede votar ni presentarse a una elección durante 5 años" }, { id: 'b' as const, text: "Puede seguir votando normalmente" }, { id: 'c' as const, text: "Solo pierde su derecho a conducir" }, { id: 'd' as const, text: "Debe abandonar el territorio francés" }] },
];
